mapper.select:
SELECT id, operator, module, operation, request_uri, request_method, request_params, ip, duration, result, error_message, created_at, updated_at, deleted FROM sys_operation_log WHERE deleted = 0
AND (operator LIKE CONCAT('%', #{keyword}, '%') OR module LIKE CONCAT('%', #{keyword}, '%') OR operation LIKE CONCAT('%', #{keyword}, '%') OR request_uri LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}
